&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Kathak.&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Pandit Birju Maharaj &lt;/strong&gt;was associated with the &lt;strong&gt;Kathak&lt;/strong&gt;&amp;nbsp;dance form.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;He was&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;a descendant of the Maharaj family&amp;nbsp;&lt;/span&gt;of&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Kathak dancers&lt;/span&gt;, which includes&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;his two uncles&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Shambhu Maharaj&amp;nbsp;&lt;/span&gt;and&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Lachhu Maharaj&lt;/span&gt;, and&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;his father&amp;nbsp;&lt;/span&gt;and&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;guru&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Acchan Maharaj&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;He was&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;born on&amp;nbsp;4 February 1938&amp;nbsp;&lt;/span&gt;in&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Handia&amp;nbsp;&lt;/span&gt;and&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;died on&amp;nbsp;17 January 2022.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;He was&amp;nbsp;awarded&amp;nbsp;Padma Vibhushan&amp;nbsp;and&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Filmfare Award for Best Choreography&amp;nbsp;&lt;/span&gt;and&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;more&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Kathak&amp;nbsp;&lt;/span&gt;is one&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;of the eight major forms of Indian classical dance&lt;/span&gt;. It is the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;classical dance form of Uttar Pradesh&lt;/span&gt;. The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;origin of Kathak&amp;nbsp;&lt;/span&gt;is traditionally&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;attributed to the travelling bards&amp;nbsp;&lt;/span&gt;in&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;ancient northern India&amp;nbsp;&lt;/span&gt;known as&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;Kathakars or storytellers&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Awards:&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;​National Film Award for Best Choreography:&lt;strong&gt;&amp;nbsp;2013&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;Sangeet Natak Akademi Awards:&lt;strong&gt; 1964&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;Filmfare Award for Best Choreography: &lt;strong&gt;2016&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;Pandit Birju Maharaj movies, filmography, biography and songs -  Cinestaan.com&quot; src=&quot;https://i2.cinestaan.com/image-bank/1500-1500/61001-62000/61938.jpg&quot; style=&quot;height: 206px; width: 250px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Bharatanatyam &lt;/strong&gt;is an ancient dancing art form from &lt;strong&gt;southern India that serves as a foundation for many other dance styles&lt;/strong&gt;.

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Rukmini Devi Arundale&lt;/strong&gt; was a well-known &lt;strong&gt;Bharatanatyam dancer in India&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Kathakali&lt;/strong&gt; is one of the world&amp;#39;s oldest theatre forms, known for its &lt;strong&gt;opulence&lt;/strong&gt;.
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Kalamandalam Gopi&lt;/strong&gt; is a well-known Kathakali dancer in India.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;Charkula dance&lt;/strong&gt; form has been practised for generations.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p style=&quot;&quot;&gt;सही उत्&amp;zwj;तर&amp;nbsp;&lt;span style=&quot;font-weight: 700; &quot;&gt;&lt;u&gt;कथक&lt;/u&gt;&lt;/span&gt; है।&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;पंडित बिरजू महाराज कथक&lt;/strong&gt; नृत्य शैली से जुड़े थे।&lt;/li&gt;
	&lt;li&gt;वह कथक नर्तकियों के &lt;strong&gt;महाराज परिवार के वंशज&lt;/strong&gt; थे, जिसमें उनके&lt;strong&gt; दो चाचा, शंभू महाराज और लच्छू महाराज, &lt;/strong&gt;और &lt;strong&gt;उनके पिता और गुरु, अचन महाराज &lt;/strong&gt;शामिल हैं।&lt;/li&gt;
	&lt;li&gt;उनका जन्म&lt;strong&gt; 4 फरवरी 1938 &lt;/strong&gt;को&lt;strong&gt; हंडिया&lt;/strong&gt; में हुआ था और उनका &lt;strong&gt;निधन 17 जनवरी 2022&lt;/strong&gt; को हुआ था।&lt;/li&gt;
	&lt;li&gt;उन्हें सर्वश्रेष्ठ &lt;strong&gt;कोरियोग्राफी के लिए पद्म विभूषण&lt;/strong&gt; और &lt;strong&gt;फिल्मफेयर पुरस्कार&lt;/strong&gt; से सम्मानित किया गया।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;कथक,&lt;/strong&gt; &lt;strong&gt;भारतीय शास्त्रीय नृत्य के आठ प्रमुख रूपों में से&lt;/strong&gt; एक है। यह उत्तर प्रदेश का शास्त्रीय नृत्य है। कथक की &lt;strong&gt;उत्पत्ति पारंपरिक रूप से प्राचीन उत्तरी भारत में यात्रा करने वाले बार्डों &lt;/strong&gt;के लिए जिम्मेदार है जिन्हें &lt;strong&gt;कथकर या कहानीकार &lt;/strong&gt;के रूप में जाना जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;पुरस्कार:&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;सर्वश्रेष्ठ कोरियोग्राफी के लिए राष्ट्रीय फिल्म पुरस्कार: &lt;strong&gt;2013&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;संगीत नाटक अकादमी पुरस्कार: &lt;strong&gt;1964&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;सर्वश्रेष्ठ कोरियोग्राफी के लिए फिल्मफेयर पुरस्कार: &lt;strong&gt;2016&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;Pandit Birju Maharaj movies, filmography, biography and songs -  Cinestaan.com&quot; src=&quot;https://i2.cinestaan.com/image-bank/1500-1500/61001-62000/61938.jpg&quot; style=&quot; height: 206px; width: 250px;&quot; /&gt;&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;भरतनाट्यम&lt;/strong&gt; &lt;strong&gt;दक्षिणी भारत का&lt;/strong&gt; एक प्राचीन नृत्य कला रूप है &lt;strong&gt;जो कई अन्य नृत्य शैलियों की नींव के रूप में कार्य करता है।&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;रुक्मिणी देवी अरुंडेल&lt;/strong&gt; भारत की एक प्रसिद्ध &lt;strong&gt;भरतनाट्यम नृत्यांगना&lt;/strong&gt; थीं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;कथकली&lt;/strong&gt; दुनिया के सबसे पुराने थिएटर रूपों में से एक है, जो अपनी &lt;strong&gt;भव्यता&lt;/strong&gt; के लिए जाना जाता है।
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;कलामंडलम गोपी&lt;/strong&gt; भारत की एक प्रसिद्ध कथकली नृत्यांगना हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;पीढ़ियों से &lt;strong&gt;चरकुला नृत्य&lt;/strong&gt; का अभ्यास किया जाता रहा है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Khel Ratna Award&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The &lt;strong&gt;National Sports Award&lt;/strong&gt; for continuous outstanding performance for four years is&amp;nbsp;&lt;/span&gt;&lt;strong&gt;Khel Ratna Award&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Khel Ratna Award:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Khel Ratna Award &lt;/strong&gt;is the &lt;strong&gt;highest sporting honor of India.&amp;nbsp;&lt;/strong&gt;It is awarded annually by the &lt;strong&gt;Ministry of Youth Affairs and Sports.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;As of 2020, the award comprises a &lt;strong&gt;medallion, a certificate,&lt;/strong&gt; and a &lt;strong&gt;cas&lt;/strong&gt;h prize of Rs 25 lakh.&lt;/li&gt;
		&lt;li&gt;Khel Ratna Award was established&amp;nbsp;in &lt;strong&gt;1991&amp;ndash;1992.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;The award since August &lt;strong&gt;6, 2021,&amp;nbsp;&lt;/strong&gt;is named after &lt;strong&gt;Major Dhyan Chand&lt;/strong&gt;, an &lt;strong&gt;Indian field hockey player&lt;/strong&gt;, widely regarded as one of the&lt;strong&gt; greatest field hockey players of all time&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;The &lt;strong&gt;Khel Ratna Award was first received&lt;/strong&gt; by &lt;strong&gt;Viswanathan Anand&lt;/strong&gt; in the chess game &lt;strong&gt;1992&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Arjuna Award:&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;The Arjuna Award&amp;nbsp;for Outstanding Performance in Sports and Games is the second-highest sporting honor of India&lt;strong&gt;.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;It was established in 1961.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Dronacharya Award:&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;​&lt;/span&gt;The Dronacharya Award&amp;nbsp;for Outstanding Coaches in Sports and Games in the sports coaching honor of the Republic of India.&lt;/li&gt;
		&lt;li&gt;It was established in 1985.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर&amp;nbsp;&lt;span style=&quot;&quot;&gt;&lt;u&gt;&lt;strong&gt;खेल रत्न पुरस्कार&lt;/strong&gt;&lt;/u&gt; है।&amp;nbsp;&lt;/span&gt;&amp;nbsp;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;चार वर्षों तक निरंतर उत्कृष्ट प्रदर्शन के लिए &lt;strong&gt;राष्ट्रीय खेल पुरस्कार&lt;/strong&gt; &lt;strong&gt;खेल रत्न पुरस्कार&lt;/strong&gt; है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;खेल रत्न पुरस्कार:&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;खेल रत्न पुरस्कार&lt;/strong&gt; &lt;strong&gt;भारत का सर्वोच्च खेल सम्मान&lt;/strong&gt; है। यह &lt;strong&gt;युवा मामले और खेल मंत्रालय&lt;/strong&gt; द्वारा प्रतिवर्ष प्रदान किया जाता है।&lt;/li&gt;
		&lt;li&gt;2020 तक, पुरस्कार में &lt;strong&gt;एक पदक, एक प्रमाण पत्र और 25 लाख रुपये का नकद पुरस्कार&lt;/strong&gt; शामिल है।&lt;/li&gt;
		&lt;li&gt;खेल रत्न पुरस्कार &lt;strong&gt;1991-1992&lt;/strong&gt; में स्थापित किया गया था।&lt;/li&gt;
		&lt;li&gt;6 अगस्त, 2021 से इस पुरस्कार का नाम &lt;strong&gt;भारतीय फील्ड हॉकी खिलाड़ी&lt;/strong&gt; &lt;strong&gt;मेजर ध्यानचंद&lt;/strong&gt; के नाम पर रखा गया है, जिन्हें व्यापक रूप से&lt;strong&gt; पुर्ण&amp;nbsp;समय के सबसे महान फील्ड हॉकी खिलाड़ियों&lt;/strong&gt; में से एक माना जाता है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;खेल रत्न पुरस्कार सबसे पहले विश्वनाथन आनंद&lt;/strong&gt; को शतरंज के खेल के लिए&amp;nbsp;&lt;strong&gt;1992&lt;/strong&gt; में मिला था।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;अर्जुन पुरस्कार:&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
